class Board:
    def __init__(self):
        self.board = np.array([
            ['b', ' ', 'b', ' ', 'b', ' ', 'b', ' '],
            [' ', 'b', ' ', 'b', ' ', 'b', ' ', 'b'],
            ['b', ' ', 'b', ' ', 'b', ' ', 'b', ' '],
            [' ', ' ', ' ', ' ', ' ', ' ', ' ', ' '],
            [' ', ' ', ' ', ' ', ' ', ' ', ' ', ' '],
            ['r', ' ', 'r', ' ', 'r', ' ', 'r', ' '],
            [' ', 'r', ' ', 'r', ' ', 'r', ' ', 'r'],
            ['r', ' ', 'r', ' ', 'r', ' ', 'r', ' ']
        ])

    def print_board(self):
        for row in self.board:
            print(' '.join(row))

    def get_piece(self, x, y):
        return self.board[x][y]

    def set_piece(self, x, y, piece):
        self.board[x][y] = piece
